228→    async fn openclaw_detect(&self) -> ServiceResult {
229→        let detection = moltis_openclaw_import::detect();
230→        match detection {
231→            Some(d) => {
232→                let scan = moltis_openclaw_import::scan(&d);
233→                tracing::info!(
234→                    home_dir = %d.home_dir.display(),
235→                    identity = scan.identity_available,
236→                    identity_agent_name = ?scan.identity_agent_name,
237→                    identity_theme = ?scan.identity_theme,
238→                    identity_user_name = ?scan.identity_user_name,
239→                    providers = scan.providers_available,
240→                    skills = scan.skills_count,
241→                    memory = scan.memory_available,
242→                    channels = scan.channels_available,
243→                    telegram_accounts = scan.telegram_accounts,
244→                    discord_accounts = scan.discord_accounts,
245→                    sessions = scan.sessions_count,
246→                    "openclaw.scan: installation detected"
247→                );
248→                Ok(serde_json::json!({
249→                    "detected": true,
250→                    "home_dir": d.home_dir.display().to_string(),
251→                    "identity_available": scan.identity_available,
252→                    "identity_agent_name": scan.identity_agent_name,
253→                    "identity_theme": scan.identity_theme,
254→                    "identity_user_name": scan.identity_user_name,
255→                    "providers_available": scan.providers_available,
256→                    "skills_count": scan.skills_count,
257→                    "memory_available": scan.memory_available,
258→                    "memory_files_count": scan.memory_files_count,
259→                    "channels_available": scan.channels_available,
260→                    "telegram_accounts": scan.telegram_accounts,
261→                    "discord_accounts": scan.discord_accounts,
262→                    "sessions_count": scan.sessions_count,
263→                    "unsupported_channels": scan.unsupported_channels,
264→                    "agent_ids": scan.agent_ids,
265→                    "agents": scan.agents,
266→                    "workspace_files_available": scan.workspace_files_available,
267→                    "workspace_files_count": scan.workspace_files_count,
268→                    "workspace_files_found": scan.workspace_files_found,
269→                }))
270→            },
271→            None => {
272→                tracing::info!("openclaw.scan: no installation detected (detect returned None)");
273→                Ok(serde_json::json!({ "detected": false }))
274→            },
275→        }
276→    }
