112→pub(super) fn gguf_backend_note(
113→    sys: &local_gguf::system_info::SystemInfo,
114→    mlx_available: bool,
115→) -> String {
116→    if mlx_available {
117→        return "MLX recommended (native Apple Silicon optimization)".to_string();
118→    }
119→
120→    let gguf_note = match gguf_acceleration_name(sys) {
121→        Some(acceleration) => format!("GGUF with {acceleration} acceleration"),
122→        None if sys.has_gpu() => "GGUF with GPU acceleration".to_string(),
123→        None => "GGUF (CPU inference)".to_string(),
124→    };
125→
126→    if sys.is_apple_silicon {
127→        format!("{gguf_note} (install mlx-lm for native MLX)")
128→    } else {
129→        gguf_note
130→    }
131→}
