134→impl LocalLlmService for LiveLocalLlmService {
135→    async fn system_info(&self) -> ServiceResult {
136→        let sys = local_gguf::system_info::SystemInfo::detect();
137→        let tier = sys.memory_tier();
138→
139→        // Check MLX availability (requires mlx-lm Python package)
140→        let mlx_available = sys.is_apple_silicon && is_mlx_installed();
141→
142→        // Detect available package managers for install instructions
143→        let installers = detect_mlx_installers();
144→        let install_commands: Vec<&str> = installers.iter().map(|(_, cmd)| *cmd).collect();
145→        let primary_install = install_commands
146→            .first()
147→            .copied()
148→            .unwrap_or("pip install mlx-lm");
149→
150→        // Determine the recommended backend
151→        let recommended_backend = if mlx_available {
152→            "MLX"
153→        } else {
154→            "GGUF"
155→        };
156→
157→        // Build available backends list
158→        let mut available_backends = vec![serde_json::json!({
159→            "id": "GGUF",
160→            "name": "GGUF (llama.cpp)",
161→            "description": gguf_backend_description(&sys),
162→            "available": true,
163→        })];
164→
165→        if sys.is_apple_silicon {
166→            let mlx_description = if mlx_available {
167→                "Optimized for Apple Silicon, fastest on Mac".to_string()
168→            } else {
169→                format!("Requires: {}", primary_install)
170→            };
171→
172→            available_backends.push(serde_json::json!({
173→                "id": "MLX",
174→                "name": "MLX (Apple Native)",
175→                "description": mlx_description,
176→                "available": mlx_available,
177→                "installCommands": if mlx_available { None } else { Some(&install_commands) },
178→            }));
179→        }
180→
181→        // Build backend note for display
182→        let backend_note = gguf_backend_note(&sys, mlx_available);
183→
184→        Ok(serde_json::json!({
185→            "totalRamGb": sys.total_ram_gb(),
186→            "availableRamGb": sys.available_ram_gb(),
187→            "hasMetal": sys.has_metal,
188→            "hasCuda": sys.has_cuda,
189→            "hasVulkan": sys.has_vulkan,
190→            "hasGpu": sys.has_gpu(),
191→            "isAppleSilicon": sys.is_apple_silicon,
192→            "memoryTier": tier.to_string(),
193→            "recommendedBackend": recommended_backend,
194→            "availableBackends": available_backends,
195→            "backendNote": backend_note,
196→            "ggufDevices": sys.gguf_devices.iter().map(|device| serde_json::json!({
197→                "index": device.index,
198→                "name": device.name,
199→                "description": device.description,
200→                "backend": device.backend,
201→                "memoryTotalBytes": device.memory_total_bytes,
202→                "memoryFreeBytes": device.memory_free_bytes,
203→            })).collect::<Vec<_>>(),
204→            "mlxAvailable": mlx_available,
205→        }))
206→    }
207→
208→    async fn models(&self) -> ServiceResult {
209→        let sys = local_gguf::system_info::SystemInfo::detect();
210→        let tier = sys.memory_tier();
211→
212→        // Get suggested model for this tier
213→        let suggested = local_gguf::models::suggest_model(tier);
214→        let suggested_id = suggested.map(|m| m.id);
215→
216→        // Get all models for this tier
217→        let available = local_gguf::models::models_for_tier(tier);
218→
219→        let models: Vec<Value> = available
220→            .iter()
