  1→//! Provider listing — `available()` implementation.
  2→
  3→use std::collections::HashMap;
  4→
  5→use serde_json::Value;
  6→
  7→use moltis_service_traits::ServiceResult;
  8→
  9→use {
 10→    super::LiveProviderSetupService,
 11→    crate::{
 12→        config_helpers::{
 13→            normalize_provider_name, ui_offered_provider_order, ui_offered_provider_set,
 14→        },
 15→        custom_providers::is_custom_provider,
 16→        key_store::normalize_model_list,
 17→        known_providers::known_providers,
 18→    },
 19→};
