	if (type === "msteams") return "Microsoft Teams";
	if (type === "discord") return "Discord";
	if (type === "slack") return "Slack";
	if (type === "whatsapp") return "WhatsApp";
	if (type === "matrix") return "Matrix";
	if (type === "nostr") return "Nostr";
	return "Telegram";
}

