				showToast(entry.known_host ? "Host pin refreshed" : "Host pinned", "success");
				await fetchSshStatus();
			})
			.catch((error) => {
				setError(error.message);
				showToast(error.message, "error");
			})
			.finally(() => {
				setBusyAction("");
				rerender();
			});
