var wsStarted = false;
function ensureWsConnected() {
	if (wsStarted) return;
	wsStarted = true;
	connectWs({
		backoff: { factor: 2, max: 10000 },
		onFrame: (frame) => {
			if (frame.type !== "event") return;
			var listeners = eventListeners[frame.event] || [];
			listeners.forEach((h) => {
				h(frame.payload || {});
			});
		},
	});
}

var WS_RETRY_LIMIT = 75;
var WS_RETRY_DELAY_MS = 200;

