			setError("Account ID is required.");
			return;
		}
		if (!secretKey.trim()) {
			setError("Secret key is required.");
			return;
		}
		var advancedPatch = parseChannelConfigPatch(advancedConfig);
		if (!advancedPatch.ok) {
			setError(advancedPatch.error);
			return;
		}
		setError(null);
		setSaving(true);
		var relayList = relays
			.split(",")
