	sessSection.appendChild(ctxRow("Key", sess.key || "unknown", true));
	sessSection.appendChild(ctxRow("Messages", String(sess.messageCount || 0)));
	sessSection.appendChild(ctxRow("Model", sess.model || "default", true));
